<body>
    <h1>Personal Expense Tracker</h1>

    <!-- Entry Form -->
    <div class="container">
        <h2>Add New Expense</h2>

        <form id="expense-form">
            <div class="form-group">
                <label for="amount">Amount ($)</label>
                <input type="number" id="amount" step="0.01" min="0.01" placeholder="Enter amount">
            </div>

            <div class="form-group">
                <label for="category">Category</label>
                <select id="category">
                    <option value="" disabled selected>Select a category</option>
                    <option value="groceries">Groceries</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>

            <div class="form-group">
                <label for="date">Date</label>
                <input type="date" id="date">
            </div>

            <div class="form-group">
                <label for="note">Note (optional)</label>
                <input type="text" id="note" placeholder="Enter note (optional)">
            </div>

            <button type="submit" id="add-expense">Add Expense</button>
        </form>

        <div id="form-error" class="error-message"></div>
    </div>

    <!-- Filters -->
    <div class="container">
        <h2>Filters</h2>

        <div class="filter-section">
            <div class="form-group">
                <label for="filter-category">Category</label>
                <select id="filter-category">
                    <option value="all">All Categories</option>
                    <option value="groceries">Groceries</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>

            <div class="form-group">
                <label for="filter-from">From Date</label>
                <input type="date" id="filter-from">
            </div>

            <div class="form-group">
                <label for="filter-to">To Date</label>
                <input type="date" id="filter-to">
            </div>
        </div>
    </div>

    <!-- Summary -->
    <div class="container">
        <h2>Summary</h2>

        <div class="total-display">
            Total: $<span id="total">0.00</span>
        </div>

        <div class="cat-summary" id="category-summary">
            <!-- Category totals will be inserted here -->
        </div>
    </div>

    <!-- Expense List -->
    <div class="container">
        <h2>Expenses</h2>

        <ul id="expense-list" class="expense-list">
            <!-- Expenses will be added here -->
        </ul>
    </div>

    <script>
        // DOM Elements
        const expenseForm = document.getElementById('expense-form');
        const amountInput = document.getElementById('amount');
        const categorySelect = document.getElementById('category');
        const dateInput = document.getElementById('date');
        const noteInput = document.getElementById('note');
        const addExpenseBtn = document.getElementById('add-expense');
        const formError = document.getElementById('form-error');

        const expenseList = document.getElementById('expense-list');
        const totalDisplay = document.getElementById('total');
        const categorySummaryContainer = document.getElementById('category-summary');

        const filterCategorySelect = document.getElementById('filter-category');
        const filterFromInput = document.getElementById('filter-from');
        const filterToInput = document.getElementById('filter-to');

        // State
        let expenses = [];

        // Constants
        const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];
        const STORAGE_KEY = 'expense_tracker_data';

        // Initialize app
        function init() {
            loadExpenses();
            renderAll();

            // Event Listeners
            expenseForm.addEventListener('submit', handleFormSubmit);

            filterCategorySelect.addEventListener('change', () => {
                applyFiltersAndRender();
            });

            filterFromInput.addEventListener('change', () => {
                applyFiltersAndRender();
            });

            filterToInput.addEventListener('change', () => {
                applyFiltersAndRender();
            });
        }

        // Load expenses from localStorage
        function loadExpenses() {
            const stored = localStorage.getItem(STORAGE_KEY);
            if (stored) {
                try {
                    expenses = JSON.parse(stored);
                } catch (e) {
                    console.error('Error parsing expenses:', e);
                    expenses = [];
                }
            }
        }

        // Save expenses to localStorage
        function saveExpenses() {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
        }

        // Validate form inputs
        function validateForm() {
            const amountValue = amountInput.value.trim();
            const categoryValue = categorySelect.value;
            const dateValue = dateInput.value;

            // Check if amount is empty
            if (!amountValue) {
                return 'Please enter an amount.';
            }

            // Parse amount as number
            const amount = parseFloat(amountValue);

            // Check if amount is NaN, zero, or negative
            if (isNaN(amount) || amount <= 0) {
                return 'Amount must be a positive number.';
            }

            // Check if category is selected
            if (!categoryValue) {
                return 'Please select a category.';
            }

            // Check if date is provided
            if (!dateValue) {
                return 'Please enter a date.';
            }

            // Validate date format (basic check)
            const dateObj = new Date(dateValue);
            if (isNaN(dateObj.getTime())) {
                return 'Please enter a valid date.';
            }

            return null; // No errors
        }

        // Handle form submission
        function handleFormSubmit(e) {
            e.preventDefault();

            // Clear previous error message
            formError.style.display = 'none';
            formError.textContent = '';

            // Validate inputs
            const errorMsg = validateForm();
            if (errorMsg) {
                formError.textContent = errorMsg;
                formError.style.display = 'block';
                return;
            }

            // Create new expense object
            const newExpense = {
                id: Date.now(),
                amount: parseFloat(amountInput.value),
                category: categorySelect.value,
                date: dateInput.value,
                note: noteInput.value.trim()
            };

            // Add to expenses array (newest first)
            expenses.unshift(newExpense);

            // Save and render
            saveExpenses();
            applyFiltersAndRender();

            // Reset form fields
            amountInput.value = '';
            categorySelect.value = '';
            dateInput.value = '';
            noteInput.value = '';
        }

        // Delete expense
        function deleteExpense(id) {
            expenses = expenses.filter(expense => expense.id !== id);
            saveExpenses();
            applyFiltersAndRender();
        }

        // Apply filters to expenses
        function getFilteredExpenses() {
            const categoryFilter = filterCategorySelect.value;
            const fromFilter = filterFromInput.value;
            const toFilter = filterToInput.value;

            return expenses.filter(expense => {
                // Category filter
                if (categoryFilter !== 'all' && expense.category !== categoryFilter) {
                    return false;
                }

                // Date range filters
                if (fromFilter || toFilter) {
                    const expenseDate = new Date(expense.date);

                    // From date check
                    if (fromFilter) {
                        const from = new Date(fromFilter);
                        // Set to end of day for inclusive filtering
                        from.setHours(0, 0, 0, 0);
                        if (expenseDate < from) {
                            return false;
                        }
                    }

                    // To date check
                    if (toFilter) {
                        const to = new Date(toFilter);
                        // Set to end of day for inclusive filtering
                        to.setHours(23, 59, 59, 999);
                        if (expenseDate > to) {
                            return false;
                        }
                    }
                }

                return true;
            });
        }

        // Calculate totals
        function calculateTotals(filteredExpenses) {
            const total = filteredExpenses.reduce((sum, expense) => sum + expense.amount, 0);

            const categoryTotals = {};
            CATEGORIES.forEach(cat => {
                categoryTotals[cat] = filteredExpenses
                    .filter(expense => expense.category === cat)
                    .reduce((sum, expense) => sum + expense.amount, 0);
            });

            return { total, categoryTotals };
        }

        // Format currency
        function formatCurrency(amount) {
            return amount.toFixed(2);
        }

        // Render all components
        function renderAll() {
            applyFiltersAndRender();
        }

        // Apply filters and render UI
        function applyFiltersAndRender() {
            const filteredExpenses = getFilteredExpenses();

            // Calculate totals
            const { total, categoryTotals } = calculateTotals(filteredExpenses);

            // Update total display
            totalDisplay.textContent = formatCurrency(total);

            // Update category summary
            categorySummaryContainer.innerHTML = '';
            CATEGORIES.forEach(cat => {
                const catTotal = categoryTotals[cat];
                if (catTotal > 0) {
                    const catElement = document.createElement('div');
                    catElement.className = 'cat-total';
                    catElement.setAttribute('data-cat', cat);
                    catElement.textContent = `${cat.charAt(0).toUpperCase() + cat.slice(1)}: $${formatCurrency(catTotal)}`;
                    categorySummaryContainer.appendChild(catElement);
                }
            });

            // Render expense list
            expenseList.innerHTML = '';

            if (filteredExpenses.length === 0) {
                const emptyMessage = document.createElement('li');
                emptyMessage.textContent = 'No expenses found.';
                emptyMessage.style.textAlign = 'center';
                emptyMessage.style.color = '#666';
                expenseList.appendChild(emptyMessage);
                return;
            }

            filteredExpenses.forEach(expense => {
                const li = document.createElement('li');
                li.className = 'expense';

                // Format date for display
                const dateObj = new Date(expense.date);
                const formattedDate = dateObj.toLocaleDateString();

                li.innerHTML = `
                    <div class="expense-info">
                        <span class="expense-amount">$${formatCurrency(expense.amount)}</span>
                        <div class="expense-details">
                            ${expense.category.charAt(0).toUpperCase() + expense.category.slice(1)} • 
                            ${formattedDate}
                            ${expense.note ? `• ${escapeHtml(expense.note)}` : ''}
                        </div>
                    </div>
                    <button class="exp-del" data-id="${expense.id}">Delete</button>
                `;

                expenseList.appendChild(li);
            });

            // Add delete event listeners
            document.querySelectorAll('.exp-del').forEach(btn => {
                btn.addEventListener('click', (e) => {
                    const id = parseInt(e.target.getAttribute('data-id'));
                    deleteExpense(id);
                });
            });
        }

        // Helper to escape HTML for security
        function escapeHtml(text) {
            if (!text) return '';
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }

        // Initialize on load
        init();
    </script>
</body>
</html>
